// Group all messages by crm_id
const groupedByContact = {};

// Group messages
items.forEach(item => {
  const crmId = item.json.crm_id;

  if (!groupedByContact[crmId]) {
    groupedByContact[crmId] = {
      crm_id: crmId,
      phone_number: item.json.phone_number,
      messages: []
    };
  }

  groupedByContact[crmId].messages.push({
    id: item.json.id,
    created_at: item.json.created_at,
    role: item.json.role,
    message: item.json.message
  });
});

// Convert to array and format messages
const output = Object.values(groupedByContact).map(contact => {
  // Sort messages by timestamp
  const sortedMessages = contact.messages.sort((a, b) => 
    new Date(a.created_at) - new Date(b.created_at)
  );

  // Format as conversation thread
  const formattedMessages = sortedMessages
    .map(m => `[${new Date(m.created_at).toLocaleString()}] ${m.role}: ${m.message}`)
    .join('\n\n---\n\n');

  // Also create a simple format
  const simpleFormat = sortedMessages
    .map(m => `${m.role}: ${m.message}`)
    .join('\n\n');

  return {
    json: {
      crm_id: contact.crm_id,
      phone_number: contact.phone_number,
      message_count: sortedMessages.length,
      messages_array: sortedMessages,
      messages_formatted: formattedMessages,
      messages_simple: simpleFormat,
      first_message_date: sortedMessages[0]?.created_at,
      last_message_date: sortedMessages[sortedMessages.length - 1]?.created_at
    }
  };
});

return output;
